(window.courseContentFiles = window.courseContentFiles || {})["archived-000002/0003"] = "<!DOCTYPE html>\r\n<html lang=\"bg\">\r\n<head>\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>d</title>\r\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\r\n  <style>\r\n    body { \r\n      font-family: \"Open Sans\", Arial, sans-serif; \r\n      max-width: 1550px; \r\n      margin: 0.5rem auto; \r\n      padding: 0 1rem; \r\n      line-height: 1.8; \r\n      color: #1f2937; \r\n    }\r\n    h1, h2, h3, h4 { \r\n      font-weight: 600; \r\n      margin-top: 0.8em;\r\n      margin-bottom: 0.3em;\r\n      color: #3a5a40;\r\n    }\r\n    h1 { font-size: 1.5em; }\r\n    h2 { font-size: 1.3em; }\r\n    h3 { font-size: 1.1em; }\r\n    h4 { font-size: 1.05em; }\r\n    h3 + h4 { margin-top: 0.3em; }\r\n    p { \r\n      margin: 0.7em 0; \r\n      white-space: pre-wrap;\r\n    }\r\n    p + ul, p + ol { margin-top: -0.5em; }\r\n    h1 + p, h2 + p, h3 + p, h4 + p,\r\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\r\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \r\n      margin-top: 0.1em; \r\n    }\r\n    ul, ol { \r\n      margin: 0.3em 0; \r\n      padding-left: 1.5em; \r\n    }\r\n    li { margin: 0.15em 0; }\r\n    ul ul { list-style-type: circle; }\r\n    ul ul ul { list-style-type: square; }\r\n    strong { font-weight: 600; }\r\n    em { font-style: italic; }\r\n    code { \r\n      background: rgba(218, 215, 205, 0.3); \r\n      padding: 2px 6px; \r\n      border-radius: 3px; \r\n      font-family: \"Courier New\", monospace; \r\n      font-size: 0.9em; \r\n    }\r\n    pre {\r\n      background: rgba(255, 255, 255, 0.5);\r\n      padding: 12px;\r\n      border-radius: 4px;\r\n      overflow-x: auto;\r\n      margin: 0.5em 0;\r\n      font-family: \"Courier New\", monospace;\r\n    }\r\n    pre code {\r\n      background: none;\r\n      padding: 0;\r\n    }\r\n    blockquote {\r\n      border-left: 3px solid #a3b18a;\r\n      padding-left: 1em;\r\n      margin: 0.5em 0;\r\n      font-style: italic;\r\n      color: #3a5a40;\r\n    }\r\n    table { \r\n      border-collapse: collapse; \r\n      margin: 0.75em 0; \r\n      width: 100%; \r\n      table-layout: auto;\r\n    }\r\n    th, td { \r\n      border: 1px solid rgba(146, 64, 14, 0.35); \r\n      padding: 6px 10px; \r\n      text-align: left; \r\n      vertical-align: top;\r\n      height: 24px;\r\n      line-height: 1.2;\r\n    }\r\n    thead th { \r\n      background: rgba(196, 127, 9, 0.08); \r\n      font-weight: 600; \r\n    }\r\n    tbody tr:nth-child(odd) { \r\n      background: rgba(146, 64, 14, 0.03); \r\n    }\r\n    img { \r\n      max-width: 100%; \r\n      height: auto; \r\n    }\r\n    a { \r\n      color: #a3b18a; \r\n      text-decoration: underline; \r\n    }\r\n    a:hover {\r\n      color: #d97706;\r\n    }\r\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\r\n    li p {\r\n      margin: 0 !important;\r\n      padding: 0 !important;\r\n      display: inline !important;\r\n      line-height: 1 !important;\r\n    }\r\n    /* Prevent nested list paragraph issues */\r\n    li > ul,\r\n    li > ol {\r\n      margin: 0.3em 0 0 0;\r\n      padding-left: 1.5em;\r\n    }\r\n    /* Ensure list structure is clean */\r\n    ul ul, ul ol,\r\n    ol ul, ol ol {\r\n      margin-top: 0.2em;\r\n      padding-left: 1.5em;\r\n    }\r\n    @media (max-width: 768px) {\r\n      body {\r\n        max-width: 100%;\r\n        margin: 0.5rem 0;\r\n        padding: 0 0.5rem;\r\n        font-size: 16px;\r\n      }\r\n      h1 { font-size: 1.3em; }\r\n      h2 { font-size: 1.1em; }\r\n      h3 { font-size: 1em; }\r\n      p { margin: 0.5em 0; }\r\n      ul, ol { padding-left: 1.2em; }\r\n      li { margin: 0.1em 0; }\r\n      table { font-size: 0.9em; }\r\n      th, td { padding: 4px 6px; }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n<h1 style=\"font-size: 1.5em;\">CYP метаболизъм</h1><table><thead><tr><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">Индуктори</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\" style=\"\">Инхибитори</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">Важни Субстрати</font></th></tr></thead><tbody><tr><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\" style=\"text-decoration-line: underline;\">Rifampicin</font> </b>(Антитуберкулозно средство)</td><td style=\"font-size: 1em;\"><b><u><font color=\"#dd0a0a\">Ketoconazole</font> </u></b>(Най-силният CYP инхибитор от системните азоли)</td><td style=\"font-size: 1em;\"><b>Нестероидни противовъзпалителни лекарства</b></td></tr><tr><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\" style=\"text-decoration-line: underline;\">Carbamazepine</font> </b>(Противоепилептично средство)</td><td style=\"font-size: 1em;\"><b><u><font color=\"#dd0a0a\">Clarithromycin</font> и Erythromycin</u>&nbsp;</b>(Макролидни антибиотици, това ги различава от Azithromycin)</td><td style=\"font-size: 1em;\"><b>H1 блокери</b></td></tr><tr><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\" style=\"text-decoration-line: underline;\">Phenytoin</font> </b>(Противоепилептично средство)</td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Chloramphenicol</b></p></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b><strong><u><font color=\"#dd0a0a\">Сулфонилурейни лекарства</font></u></strong></b></p></td></tr><tr><td style=\"font-size: 1em;\"><b><u style=\"\">Phenobarbital</u> </b>(Барбитурат, индуцира и глюкуронилтрансферазата)</td><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\" style=\"text-decoration-line: underline;\">Ritonavir</font> </b>(Протеазен инхибитор)</td><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\"><u></u></font></b><p style=\"font-size: 1em;\"><b><u><font color=\"#dd0a0a\">Естрогени</font></u></b></p></td></tr><tr><td style=\"font-size: 1em;\"><b>Griseofulvin </b>(Антимикотик)</td><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\" style=\"\"><u>Amiodarone</u> </font></b>(Антиаритмично средство)</td><td style=\"font-size: 1em;\"><b><u>Codeine</u> </b>(частичен метаболизъм до морфин)</td></tr><tr><td style=\"font-size: 1em;\"><b>Nevirapine </b>(Антиретровирусно средство, ненуклеозиден инхибитор)</td><td style=\"font-size: 1em;\"><b><u><font color=\"#dd0a0a\">Cimetidine</font></u> </b>(H2-блокер при Язва)</td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Oxycodone</b></p> </td></tr><tr><td style=\"font-size: 1em;\"><b>Тютюнопушене</b></td><td style=\"font-size: 1em;\"><b>Fluconazole </b>(Азолен антимикотик)</td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b><u>Инхибитори на фактор Xa </u></b>(Rivaroxaban, Apixaban, Edoxaban)</p> </td></tr><tr><td style=\"font-size: 1em;\"><b>Dexamethasone </b>(Глюкокортикостероид)</td><td style=\"font-size: 1em;\"><b>Verapamil </b>(Калциев антагонист)</td><td style=\"font-size: 1em;\"><b>Methadone</b></td></tr><tr><td style=\"font-size: 1em;\"><b>Primidone </b>(Противоепилептично средство)</td><td style=\"font-size: 1em;\"><b>Сок от грейпфрут</b></td><td style=\"font-size: 1em;\"><b>Всички амиди като местни анестетици </b>(Lidocaine, Mepivacaine, Bupivacaine)</td></tr><tr><td style=\"font-size: 1em;\"></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Ciprofloxacin</font> и Norfloxacin</strong> (Хинолонови антибиотици)</p></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b><u>Бензодиазепини</u> </b>(Midazolam, Cinolazepam, Flunitrazepam)</p> </td></tr><tr><td style=\"font-size: 1em;\"></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Conivaptan </b>(антагонист на АДХ)</p></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><strong style=\"text-decoration-line: underline;\"><font color=\"#dd0a0a\">Кумаринови антикоагуланти</font></strong> (Acenocoumarol, Warfarin)</p></td></tr><tr><td style=\"font-size: 1em;\"></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Metronidazole </b>(нитромидазоли)</p></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Антипсихотици, трициклични антидепресанти</b></p> </td></tr><tr><td style=\"font-size: 1em;\"></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Сулфонамиди </b>(Sulfamethoxazole +Trimethoprim = Co-trimoxazole, Sulfasalazine, Sulfathiazole)</p></td><td style=\"font-size: 1em;\"><b><u>Статинит</u>е -&nbsp;риск от рабдомиолиза<u><br></u></b>(Lovastatin, Simvastatin, Fluvastatin, Atorvastatin, Rosuvastatin без Pravastatin)&nbsp;</td></tr><tr><td style=\"font-size: 1em;\"></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Макролиди </b>(I поколение:Erythromycin, Spiramycin &amp; II поколение: Clarithromycin, Azithromycin, Midecamycin, Roxithromycin)</p></td><td style=\"font-size: 1em;\"> </td></tr><tr><td style=\"font-size: 1em;\"></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\">Valproic acid</font></b></p></td><td style=\"font-size: 1em;\"></td></tr><tr><td style=\"font-size: 1em;\"></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Lomitapide </b>(Лекарства понижаващи non-HDL-C)</p></td><td style=\"font-size: 1em;\"></td></tr><tr><td style=\"font-size: 1em;\"></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>SSRI </b>(Fluoxetine, Paroxetine, Sertraline, Fluvoxamine, Citalopram, Escitalopram)</p></td><td style=\"font-size: 1em;\"></td></tr></tbody></table><br><table><thead><tr><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">Антибиотик/химиотерапевтик</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">Спектър</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">G(+) коки</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">G(+) бацили</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">G(-) коки</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">G(-) бактерии</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">G(-) извити</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">Интрацелуларни</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">Забележка</font></th></tr></thead><tbody><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Пеницилини<br>Механизъм: инхибират синтезата на бактериалната клетъчна стена</font></b></td></tr><tr><td style=\"font-size: 1em;\"><p style=\"\"><b>Benzylpenicillin, Phenoxymethylpenicillin</b></p></td><td style=\"font-size: 1em;\">тесен</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\"><font color=\"#3a5a40\"><b>-</b></font></td><td style=\"font-size: 1em;\"><font color=\"#3a5a40\"><b>-</b></font></td><td style=\"font-size: 1em;\">T. pallidum</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">C. diphtheriae, B. anthracis, Clostridia, Actinomyces, L. monocytogenes. T. Pallidum, <b>без S. aureus</b></td></tr><tr><td style=\"font-size: 1em;\"><b>Бета-лактамазо устойчиви<br>Meticillin, Oxacillin</b></td><td style=\"font-size: 1em;\">тесен</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\"><b>+ S. aureus</b></td></tr><tr><td style=\"font-size: 1em;\"><b>Аминопеницилини<br>Ampicillin, Amoxicillin</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">H.pylori</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+ <b>Neisseria</b>, Streptococci, Enterococci, Listeria, H. Influenzae, Enterobactericae (E. Coli и др.)</td></tr><tr><td style=\"font-size: 1em;\"><b>Co-Amoxiclav</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\"><b>+ S. aureus</b></td></tr><tr><td style=\"font-size: 1em;\"><b>Карбоксипеницилини<br>Carbenicillin</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">K. pneumoniae, <b>P. aeruginosa</b>, Proteus indol (+)</td></tr><tr><td style=\"font-size: 1em;\"><b><p>Aцилуреидопеницилини</p>Piperacillin<br></b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\"><b>P. aeruginosa</b>, K. Pneumoniae, Acinetobacter</td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Цефалоспорини<br><p style=\"font-size: 1em;\">Механизъм: инхибират синтезата на бактериалната клетъчна стена</p></font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>I генерация<br>Завършват на in, il</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\"><b>Без Enterococci!</b> От G(-): E. Coli, Proteus, K. Pneumoniae</td></tr><tr><td style=\"font-size: 1em;\"><b>II генерация<br>Cef-uroxime, -amandole, aclor</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">понижена активност спрямо S. aureus, H. Influenzae, <b>анаероби!</b></td></tr><tr><td style=\"font-size: 1em;\"><b>III генерация<br>Cefepime</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">повишена активност спрямо S. pneumoniae, G(-), <b>P. aureginosa</b></td></tr><tr><td style=\"font-size: 1em;\"><b>IV генерация<br>Ceftaroline</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">Висока стабилност към бета-лактамази</td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Карбапенеми</font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Imipenem, Meropenem</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">Висока устойчивост към бета-лактамази, <b>резервни антибиотици</b></td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Гликопептиди<br>Механизъм:&nbsp;инхибират синтезата на бактериалната клетъчна стена</font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Vancomycin, Teicoplanin</b></td><td style=\"font-size: 1em;\">тесен</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">Streptococci (вкл. <b>PRSP</b>), Staphylococci (вкл. <b>MRSA</b>), Cl. difficile, Enterococci</td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Аминогликозиди<br>Механизъм:&nbsp;потискат белтъчната синтеза, в рибозомите</font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Gentamycin, Tobramycin, Streptomycin, Amikacin<br>Neomycin за локално</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">P. Aeruginosa, K. Pneumoniae, E. Coli, Enterobacter, Proteus, Serratia, S. Aureus, M. Tuberculosae</td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Fosfomycin<br><p style=\"font-size: 1em;\">Механизъм:&nbsp;инхибират синтезата на бактериалната клетъчна стена</p></font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Fosfomycin</b></td><td style=\"font-size: 1em;\">тесен</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\"><b>Уропатогени</b></td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Флуорирани хинолони<br><p style=\"font-size: 1em;\">Механизъм:&nbsp;инхибират ДНК гираза</p></font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>I генерация<br>Ciprofloxacin, Norfloxacin, Ofloxacin</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">H. Influenzae, Neisseria, <b>P. Aeruginosa </b>(Cipro-), MSSA (Cipro-, Oflo-)</td></tr><tr><td style=\"font-size: 1em;\"><b>II генерация<br>Moxifloxacin, Levofloxacin</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">L. pneumophyla, M. pneumoniae, C. Pneumoniae M. Tuberculosis (Moxi-), Анаероби, <b>атипична пневмония</b></td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Тетрациклини<br><p style=\"font-size: 1em;\">Механизъм:&nbsp;потискат белтъчната синтеза, в рибозомите</p></font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Tetracycline, Doxycycline</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">Enterobacteriaceae, <b>H. influenzae</b>, Brucella, V.Cholerae, Rickettsia, Chlamydia, M. Pneumoniae, Ureapl., T. pallidum, B. Burgdorferi, първаци (амеби)</td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Макролиди:<br><p style=\"font-size: 1em;\">Механизъм:&nbsp;потискат белтъчната синтеза, в рибозомите</p></font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>I генерация<br>Erythromycin, Spiramycin</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">G(+) коки и бактерии, N. gonorrheae, Михоплазми, Хламидии, L. Pneumoniae, T. Pallidum</td></tr><tr><td style=\"font-size: 1em;\"><b>II генерация<br>Clarithromycin, Azithromycin, <br>Midecamycin, Roxithromycin</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\"><b>H.pylori</b></td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+ <b>H. influenzae</b>; B. Burgdorferi, T. gondii, MAC (A, C), <b>H. Pylori </b>(<b>Clarithromycin</b>)</td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Амфениколи:<br><p style=\"font-size: 1em;\">Механизъм:&nbsp;потискат белтъчната синтеза, в рибозомите</p></font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Chloramphenicol</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">Подобен на тетрациклини + <b>анаероби</b></td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Линкозамиди:<br><p style=\"font-size: 1em;\">Механизъм:&nbsp;потискат белтъчната синтеза, в рибозомите</p></font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Clindamycin, Lincomycin</b></td><td style=\"font-size: 1em;\">тесен</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">G(+) коки (вкл. S. aureus), <b>Анаероби</b> (вкл. B. Fragilis, но без Cl. diffcile),&nbsp;<strong style=\"white-space-collapse: preserve;\">Pneumocystis Jirovecii</strong><span style=\"white-space-collapse: preserve;\">, Toxoplasma gondii</span></td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Сулфонамиди<br>Механизъм: блокират етапи в синтезата на фолиева киселина</font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Co-Trimoxazol, Sulfasalazine, Sulfathiazole</b></td><td style=\"font-size: 1em;\">широк</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">G(+) и G(-) коки и бактерии, Хламидии, Първаци, Nocardia, <b>Pneumocystis Jirovecii</b>, Toxoplasma gondii</td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Оксазолидинони:<br><p style=\"font-size: 1em;\">Механизъм:&nbsp;потискат белтъчната синтеза, в рибозомите</p></font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Linezolid</b></td><td style=\"font-size: 1em;\">тесен</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\"><b>MRSA, PRSP, VRE, анаероби</b></td></tr><tr><td colspan=\"10\" style=\"text-align: center; font-size: 1em;\"><b><font color=\"#3a5a40\">Нитроимидазоли<br><p style=\"font-size: 1em;\">Механизъм:&nbsp;потискат белтъчната синтеза и продуцират метаболити, токсични за бактериалната клетка</p></font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Metronidazole</b></td><td style=\"font-size: 1em;\">тесен</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\">+</td><td style=\"font-size: 1em;\"><b>H. pylori</b></td><td style=\"font-size: 1em;\">-</td><td style=\"font-size: 1em;\"><b>Анаероби</b>, <b>първаци</b></td></tr></tbody></table><h3 style=\"font-size: 1.1em;\">Нежелани реакции на антибиотици:</h3><p><b>Пеницилини: </b></p><ul><li>Почти пълна липса на органна токсичност - <font color=\"#dd0a0a\">безопасни при бременни</font></li><li><font color=\"#dd0a0a\">Чести алергични реакции</font></li></ul><p><b>Цефалоспорини:</b></p><ul><li>Алергични реакции</li><li>Cefoperazone и Cefamadole: дисулфам реакции с алкохол, потискат синтеза на витамин К -&gt; хипопротромбинемия и кървене</li></ul><div><b>Карбапенеми:</b></div><ul><li>Алергични реакции</li><li>Във високи дози Imipenem води до гърчове</li></ul><div><b>Гликопептиди:</b></div><ul><li><font color=\"#dd0a0a\">Ото- и нефротоксичност</font></li><li>Синдром на червения човек</li></ul><div><b>Аминогликозиди:</b></div><ul><li><p><font color=\"#dd0a0a\">Ото- и нефротоксичност</font></p></li><li><p>Кураре-подобен ефект -&gt; невромускулен блок -&gt; риск от дихателна парализа с периферни миорелаксанти</p></li><li><p>Тератогенни</p></li></ul><div><b>Fosfomycin:</b></div><ul><li>Безопасен при бременни</li></ul><div><b>Флуорирани хинолопни:</b></div><ul><li>ГИТ нарушения, ЦНС нежелани ефекти като замаяност и други, Периферна невропатия, Алергични реакции</li><li>Удължаване на QT интервала - Levofloxacin и Moxifloxacin</li><li>Увреждания на опорно-двигателната система</li><li>Хепатотоксичност</li><li>Не са подходящи за бременни</li><li>Ciprofloxacin и Norfloxacin инхибират CYP</li></ul><div><b>Тетрациклини:</b></div><ul><li><p><font color=\"#dd0a0a\">Натрупване в костите и зъбите</font> - оцветяване на зъбите, кариес</p></li><li><p>Фоточувствителност (Doxycycline).</p></li><li><p>Нефро- и хепатотоксичност</p></li></ul><div><b>Chloramphenicol:</b></div><ul><li><p><font color=\"#dd0a0a\">Доза-зависимо потискане на костния мозък с апластична анемия</font></p></li><li><p>Синдром на сивото бебе</p></li><li><p><font color=\"#dd0a0a\">Ензимен инхибитор</font></p></li><li><p>Дисулфам реакции</p></li></ul><div><b>Макролиди:</b></div><ul><li>Увреждане на слуха, тинитус</li><li>Удължаване на QT интервала</li><li><font color=\"#dd0a0a\">Инхибитори на CYP и P-gp</font></li></ul><div><b>Линкозамиди:</b></div><ul><li>Алергични, езофагит</li></ul><div><b>Сулфонамиди:</b></div><ul><li>Алергични реакции, кръстостана свръхчувствителност</li><li>Хематологични - мегалобластна анемия, <font color=\"#dd0a0a\">хемолзиа при Г6ФДХ дефицит</font></li><li>Кристалурия</li></ul><div><b>Linezolid:</b></div><ul><li>Хематологични - анемия, панцитопения</li><li>Митохондриална токсичност - периферна и оптична невропатия, лактатна ацидоза</li><li><font color=\"#dd0a0a\">Инхбитор на МАО - риск от серотонинов синдром</font></li></ul><div><b>Metronidazole:</b></div><ul><li><p>Стомашно-чревни – гадене, диария, стоматит, метален вкус.</p></li><li><p>НС – периферна невропатия, възможни енцефалопатия, атаксия, гърчове</p></li><li><p>Дисулфам реакции</p></li><li><p><font color=\"#dd0a0a\">Инхибитор на CYP</font></p></li></ul><h3 style=\"font-size: 1.1em;\">Бременни жени:</h3><table><thead><tr><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">Забранено</font></th><th style=\"font-size: 1em;\"><font color=\"#3a5a40\">Позволено</font></th></tr></thead><tbody><tr><td style=\"font-size: 1em;\"><b> Methotrexate</b></td><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\"> Paracetamol</font>, <font color=\"#dd0a0a\">Ibuprofen</font></b></td></tr><tr><td style=\"font-size: 1em;\"><b> Ergotamine</b></td><td style=\"font-size: 1em;\"><font color=\"#dd0a0a\"><b>Methyldopa:</b> </font>за хипертония при бременни</td></tr><tr><td style=\"font-size: 1em;\"><b> Morphine</b></td><td style=\"font-size: 1em;\"> <b>Lamotrigine </b>предпочитан</td></tr><tr><td style=\"font-size: 1em;\"><b>Антиепилептични лекарства </b>\r\n(Carbamazepine, Phenytoin, Valproic acid, Ethosuximide, Phenobarbital, Clonazepam, Clorazepate, Diazepam, Lamotrigine, Gabapentin, Pregabaline, Tiagabine, Topiramate, Levetiracetam)\r\n<b>Lamotrigine </b>се приема за най-безопасен</td><td style=\"font-size: 1em;\"><b>Калциеви антагонисти</b></td></tr><tr><td style=\"font-size: 1em;\"><b>ACE инхибитори </b>(-pril лекарства)</td><td style=\"font-size: 1em;\"><b>Бета-блокери</b></td></tr><tr><td style=\"font-size: 1em;\"><b>Директни ренинови инхибитори </b>(Aliskiren)</td><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\">Heparin и подобни</font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Тиазиди и подобни </b>(Hydrochlorothiazide, Chlorthalidone, Indapamide)</td><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\">Пеницилини</font></b></td></tr><tr><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Инхибитори на HMG-CoA редуктаза</b> (Статини)</p></td><td style=\"font-size: 1em;\"><b>Цефалоспорини</b></td></tr><tr><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\">Кумаринови антикоагуланти</font></b> (Acenocoumarol, Warfarin)</td><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\">Fosfomycin</font></b></td></tr><tr><td style=\"font-size: 1em;\"><b>Аминогликозиди </b>(Gentamicin, Tobramycin, Streptomycin, Neomycin, Amikacin)</td><td style=\"font-size: 1em;\"><b>Aciclovir, Valaciclovir, Famciclovir</b> (за превенция на herpes simplex virus през бремеността)</td></tr><tr><td style=\"font-size: 1em;\"><b>Флуорирани хинолони</b> (I поколение: Ciprofloxacin, Norfloxacin, Ofloxacin &amp; II поколение: Levofloxacin, Moxifloxacin)</td><td style=\"font-size: 1em;\"><b>Нуклеозидни лекарства </b>за бременни със <b>СПИН </b>(Zidovudine, Lamivudine, Abecavir)</td></tr><tr><td style=\"font-size: 1em;\"><b>Тетрациклини</b> (Tetracycline, Doxycycline)</td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><strong>Протеазни инхибитори </strong>за бременни със <strong>СПИН </strong>(Atazanavir, Darunavir)</p></td></tr><tr><td style=\"font-size: 1em;\"><b>Системно приложение на азоли</b></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><strong>Интегразни инхибитори </strong>за бременни със <strong>СПИН </strong>(Dolutegravir, Raltegravir)</p></td></tr><tr><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Clomiphene</b>: многоплодна бременност</p></td><td style=\"font-size: 1em;\"><b>Лекарства за хепатит B </b>(Entecavir, Tenofovir)</td></tr><tr><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><strong>Mifepristone </strong>(с гестагенна активност) + <strong><font color=\"#dd0a0a\">Misoprostol </font></strong>(аналог на PGE1): за аборт</p></td><td style=\"font-size: 1em;\"><b>Progesterone</b>: протектор на бремеността</td></tr><tr><td style=\"font-size: 1em;\"></td><td style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\">Инхибитори на протонната помпа</font></b> (Omeprazole, Esomeprazole, Pantoprazole, Lansoprazole)</p></td></tr><tr><td style=\"font-size: 1em;\"><br></td><td style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\">Железни препарати</font></b></td></tr></tbody></table><script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script><script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script><script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script><h3 style=\"font-size: 1.1em;\">Микози:</h3><ul><li style=\"font-size: 1em;\"><b>Kандидоза </b>- <font color=\"#dd0a0a\">Nystatin</font>, Clotrimazole, Econazole, <font color=\"#dd0a0a\">Fluconazole</font></li><li style=\"font-size: 1em;\"><b>Дерматомикоза </b>- Griseofulvin, <font color=\"#dd0a0a\">Ketoconazole</font>, <font color=\"#dd0a0a\">Naftitine</font>, <font color=\"#dd0a0a\">Miconazole</font>, Terbinafine, Ciclopirox Alamine, Amorolfine</li><li style=\"font-size: 1em;\"><b>Онихомикоза </b>- Griseofulvin, <font color=\"#dd0a0a\">Itraconazole</font>, <font color=\"#dd0a0a\">Terbinafine</font>, <font color=\"#dd0a0a\">Ciclopirox Alamine</font>, <font color=\"#dd0a0a\">Amorolfine</font></li></ul><h3 style=\"font-size: 1.1em;\">Туберкулоза:</h3><p style=\"font-size: 1em;\"><b>Лекарства от първи ред:</b></p><ul><li style=\"font-size: 1em;\"><b>Rifampicin</b>:</li><ul><li style=\"font-size: 1em;\"><b>Механизъм</b>: бактерицидно, инхибира ДНК-зависимата РНК полимераза</li><li style=\"font-size: 1em;\"><b>Недостатъци</b>: <font color=\"#dd0a0a\">хепатотоксичност</font>, <font color=\"#dd0a0a\">оранжево</font>-<font color=\"#dd0a0a\">червено оцветяване </font>на телесните течности, мощен индуктор на CYP</li></ul><li style=\"font-size: 1em;\"><b>Isoniazid</b>:</li><ul><li style=\"font-size: 1em;\"><b>Механизъм</b>: бактерицидно, инхибира синтеза на миколова киселина.</li><li style=\"font-size: 1em;\"><b>Особеност</b>: метаболизира се от ацетилиране от <font color=\"#dd0a0a\">генетично полиморфната N-ацетилтрансфераза 2</font>, която разделя хората на бързи и бавни ацетилатори</li><li style=\"font-size: 1em;\"><b>Недостатъци</b>: <font color=\"#dd0a0a\">хепатотоксичност</font>, <font color=\"#dd0a0a\">периферна невропатия </font>(прилага се с пиридоксин - витамин B6 за да се намали)</li></ul><li style=\"font-size: 1em;\"><b>Ethambutol</b>:</li><ul><li style=\"font-size: 1em;\"><b>Механизъм</b>: бактериостатично, инхибира синтеза на арабиногалактан</li><li style=\"font-size: 1em;\"><b>Особеност</b>: <p style=\"font-size: 1em;\">Основната му роля е да предотвратява развитието на резистентност към другите лекарства в схемата.</p></li><li style=\"font-size: 1em;\"><b>Недостатъци</b>: <font color=\"#dd0a0a\">очен неврит </font>с нарушено цветно усещане</li></ul><li style=\"font-size: 1em;\"><b>Pyrazinamide</b>:</li><ul><li style=\"font-size: 1em;\"><b>Механизъм</b>: бактериоцидно, активен в кисела среда, <p style=\"font-size: 1em;\">ефективен срещу нерепликиращи се микобактерии, разположени вътре в макрофагите и в казеозната тъкан на туберкулозните лезии.</p></li><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Недостатъци</b>: <font color=\"#dd0a0a\">хепатотоксичност</font>, <font color=\"#dd0a0a\">хиперурикемия </font>до подагра или атралгия</p></li></ul></ul><p style=\"font-size: 1em;\"><b>Лекарства от втори ред:</b></p><ul><li style=\"font-size: 1em;\"><b>Streptomycin (аминогликозид):</b></li><ul><li style=\"font-size: 1em;\"><b>Механизъм</b>: <p style=\"font-size: 1em;\">бактерицидно, инхибира синтеза на протеини</p></li><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Недостатъци</b>: <font color=\"#dd0a0a\">ототоксичност </font>и <font color=\"#dd0a0a\">нефротоксичност</font></p></li></ul><li style=\"font-size: 1em;\"><b>Clarithromycin </b>(<b>макролид</b>):</li><ul><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Механизъм</b>: </p><p style=\"font-size: 1em;\">бактериостатично, инхибира протеиновия синтез</p></li><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Особености</b>: </p><p style=\"font-size: 1em;\">Основно се използва за лечение на инфекции, причинени от <font color=\"#dd0a0a\">нетипични микобактерии </font>(напр. Mycobacterium avium complex - MAC), особено при пациенти с <font color=\"#dd0a0a\">HIV</font>/<font color=\"#dd0a0a\">СПИН</font>. </p><p style=\"font-size: 1em;\">Рядко се включва в схемите за лечение на Mycobacterium tuberculosis.</p></li></ul><li style=\"font-size: 1em;\"><b>Флуорирани хинолони (Levofloxacin, Moxifloxacin):</b></li><ul><li style=\"font-size: 1em;\"><b>Механизъм</b>: <p style=\"font-size: 1em;\">бактерицидно, инхибират ключови бактериални ензими – ДНК-гираза и топоизомераза IV,</p></li><li style=\"font-size: 1em;\"><b>Особености</b>: <p style=\"font-size: 1em;\">Те са критични лекарства при лечението на<font color=\"#dd0a0a\"> мултирезистентна туберкулоза</font> (MDR-TB).</p></li><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Недостатъци</b>: </p><p style=\"font-size: 1em;\"><font color=\"#dd0a0a\">СЧ нарушения</font>.<font color=\"#dd0a0a\"> </font></p><p style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Продължаване на QT интервала</font> (риск от аритмии). </p><p style=\"font-size: 1em;\">Рядко: <font color=\"#dd0a0a\">увреждане и</font> <font color=\"#dd0a0a\">руптура на сухожилията </font>(напр. Ахилесовото сухожилие).</p></li></ul></ul><h3 style=\"font-size: 1.1em;\">Антидоти:</h3><ul><li style=\"font-size: 1em;\"><b>Paracetamol </b>- <b><font color=\"#dd0a0a\">Acetylcysteine</font></b></li><li style=\"font-size: 1em;\"><b>Бензодиазепени </b>- <b><font color=\"#dd0a0a\">Flumanezil</font></b></li><li style=\"font-size: 1em;\"><b>Хепарин и подобни </b>- <b><font color=\"#dd0a0a\">Protamine sulfate</font></b></li><li style=\"font-size: 1em;\"><b>Инхибиотири на фактор Xa</b> (Rivaroxaban, Apixaba, Edoxaban) - <b><font color=\"#dd0a0a\">Andexanet alfa</font></b></li><li style=\"font-size: 1em;\"><b>Директни инхибитори на тормбина/фактор IIa</b> (Dabigatran) - <b><font color=\"#dd0a0a\">Idarucizumab</font></b></li><li style=\"font-size: 1em;\"><b>Кумаринови антикоагуналтни </b>(Acenocoumarol, Warfarin) - <font color=\"#dd0a0a\"><b>Phytomenadione</b> </font>(вит. K1)</li><li style=\"font-size: 1em;\"><b>Железни препарати </b>- <b><font color=\"#dd0a0a\">Deferoxamine</font></b></li><li style=\"font-size: 1em;\"><b>М-холиномиметици/Антихоленестеразни лекарства - <font color=\"#dd0a0a\">Atropine</font></b></li><li style=\"font-size: 1em;\"><b>Фосфоорганични съединения - <font color=\"#dd0a0a\">Atropine</font>, <font color=\"#dd0a0a\">Obidoxome</font></b></li><li style=\"font-size: 1em;\"><b>Atropine - <font color=\"#dd0a0a\">Galantamine</font>, <font color=\"#dd0a0a\">Neostigmine</font></b></li><li style=\"font-size: 1em;\"><b>Неспецифични антидоти:</b></li><ul><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\">Лекарства, намаляващи резорбцията на токсичния агент в гастроинтестиналния тракт: carbo</p><p style=\"font-size: 1em;\">activatus (активен въглен) – универсален антидот</p></li><li style=\"font-size: 1em;\">Невропротективни лекарства (piracetam, vitamin B6)</li><li style=\"font-size: 1em;\">Антиоксиданти и хепатопротективни лекарства (<font color=\"#dd0a0a\">aсetylcysteine</font>, ademetionine, <font color=\"#dd0a0a\"><b>silymarin</b></font>)</li><li style=\"font-size: 1em;\">Лаксативи – magnesium sulfate</li><li style=\"font-size: 1em;\">Диуретици – furosemide</li></ul></ul><table><tbody><tr><td style=\"font-size: 1em;\"><strong>Лекарствена група (превод)</strong></td><td style=\"font-size: 1em;\"><strong>Нежелани лекарствени реакции (НЛР) / Токсичен синдром</strong></td></tr><tr><td style=\"font-size: 1em;\"><strong>M-холиномиметици / Антихолинестеразни лекарства</strong></td><td style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Бронхоспазъм</font>, <font color=\"#dd0a0a\">саливация</font>, сълзене, <font color=\"#dd0a0a\">брадикардия</font>, <font color=\"#dd0a0a\">гадене </font>и <font color=\"#dd0a0a\">повръщане</font>, диария. <font color=\"#dd0a0a\">Миоза</font>. <font color=\"#dd0a0a\">Възбуждение</font>, <font color=\"#dd0a0a\">гърчове </font>и кома при предозиране. <font color=\"#dd0a0a\">Парализа в напреднал стадий</font>, вкл. на респираторната мускулатура.</td></tr><tr><td style=\"font-size: 1em;\"><strong>M-холиноблокери</strong></td><td style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Тахикардия</font>, <font color=\"#dd0a0a\">сухота </font>в <font color=\"#dd0a0a\">устата</font>, ретенция на урината, <font color=\"#dd0a0a\">запек</font>, суха и топла кожа, хипертермия. <font color=\"#dd0a0a\">Мидриаза</font>, парализа на акомодацията (замъглено зрение), <font color=\"#dd0a0a\">повишено вътреочно налягане</font>. <font color=\"#dd0a0a\">Объркване</font>, забравяне, <font color=\"#dd0a0a\">халюцинации</font>, делир, кома.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Бета-адреноблокери</strong></td><td style=\"font-size: 1em;\">Намален физически капацитет, умора. Хипогликемия. Периферна вазоконстрикция - <font color=\"#dd0a0a\">студени крайници </font>(неселективни &gt; селективни). <font color=\"#dd0a0a\">Бронхоспазъм </font>(при астма). ЦНС: <font color=\"#dd0a0a\">забавени рефлекси</font>, <font color=\"#dd0a0a\">кошмари</font>. <font color=\"#dd0a0a\">Rebound ефект</font> при рязко спиране. <font color=\"#dd0a0a\">Брадикардия и сърдечна недостатъчност до AV блок</font>.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Нестероидни противовъзпалителни лекарства</strong></td><td style=\"font-size: 1em;\">Гадене и повръщане, язва, кървене от гастроинтестиналния тракт. <font color=\"#dd0a0a\">Аналгетична нефропатия </font>(хронично) или остра бъбречна недостатъчност (предозиране). Задръжка на сол и вода, <font color=\"#dd0a0a\">хиперкалиемия</font>. <font color=\"#dd0a0a\">Алергични реакции</font>. ЦНС: сънливост, атаксия, делир. Салицилати: шум в ушите, хипервентилация, метаболитна ацидоза.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Paracetamol</strong></td><td style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Хепатотоксичност </font>при предозиране.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Опиоидни аналгетици</strong></td><td style=\"font-size: 1em;\">Гадене, повръщане, <font color=\"#dd0a0a\">запек</font>, ретенция на урината. <font color=\"#dd0a0a\">Бронхоспазъм</font>, сърбеж. <font color=\"#dd0a0a\">Миоза</font>. Потискане на дишането и кома при предозиране. <font color=\"#dd0a0a\">Лекарствена зависимост</font>, <font color=\"#dd0a0a\">еуфория</font>, <font color=\"#dd0a0a\">седация</font>.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Глюкокортикостероиди</strong></td><td style=\"font-size: 1em;\">Емоционална лабилност, смущения в съня. <font color=\"#dd0a0a\">Повишен апетит</font>, наддаване на <font color=\"#dd0a0a\">тегло</font>, <font color=\"#dd0a0a\">захарен диабет</font>. <font color=\"#dd0a0a\">Хипертония</font>. <font color=\"#dd0a0a\">Язвена болест</font>. <font color=\"#dd0a0a\">Остеопороза</font>, остеонекроза. Изтъняване на кожата, лошо зарастване на рани. <font color=\"#dd0a0a\">Атрофия </font>на<font color=\"#dd0a0a\"> надбъбрека</font>. Катаракта.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Седативно-сънотворни и анксиолитици</strong></td><td style=\"font-size: 1em;\">Объркване, замайване, <font color=\"#dd0a0a\">сънливост</font>, атаксия, намален мускулен тонус, <font color=\"#dd0a0a\">амнезия</font>, хипотония,<font color=\"#dd0a0a\"> респираторна депресия</font>, кома. <font color=\"#dd0a0a\">Лекарствена зависимост.</font></td></tr><tr><td style=\"font-size: 1em;\"><strong>Антипсихотични лекарства</strong></td><td style=\"font-size: 1em;\">Екстрапирамидни симптоми (<font color=\"#dd0a0a\">паркинсонизъм</font>, акатизия, дистония, късна <font color=\"#dd0a0a\">дискинезия</font>). Ортостатична хипотензия. Напълняване, метаболитен синдром. <font color=\"#dd0a0a\">Хиперпролактинемия</font>. <font color=\"#dd0a0a\">Агранулоцитоза </font>(<font color=\"#dd0a0a\">clozapine</font>).</td></tr><tr><td style=\"font-size: 1em;\"><strong>Трициклични антидепресанти</strong></td><td style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Атропиноподобни ефекти</font> (<font color=\"#dd0a0a\">сухота</font>, <font color=\"#dd0a0a\">запек</font>). <font color=\"#dd0a0a\">Седация</font>, <font color=\"#dd0a0a\">атаксия</font>. Предозиране: <font color=\"#dd0a0a\">тахикардия</font>, <font color=\"#dd0a0a\">аритмии</font>, <font color=\"#dd0a0a\">гърчове</font>, <font color=\"#dd0a0a\">кома</font>.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Психостимуланти (cocain, amphetamine, MDMA)</strong></td><td style=\"font-size: 1em;\">Възбуда, конвулсии, психоза. Хипертония, тахиаритмия, инсулт. Мидриаза. Хипертермия. <font color=\"#dd0a0a\">Серотонинов синдром</font>, хипонатриемия (MDMA).</td></tr><tr><td style=\"font-size: 1em;\"><strong>Сърдечни гликозиди</strong></td><td style=\"font-size: 1em;\">Токсичен синдром: гадене, повръщане, объркване, зрителни нарушения (<font color=\"#dd0a0a\">ксантопсия </font>- виждане в жълто); <font color=\"#dd0a0a\">брадикардия</font>, <font color=\"#dd0a0a\">AV блок</font>, <font color=\"#dd0a0a\">опасни камерни аритмии</font>.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Анаболни стероиди</strong></td><td style=\"font-size: 1em;\">Хепатотоксичност. Психични нарушения. Азооспермия, инфертилитет. Повишен сърдечносъдов риск.</td></tr><tr><td style=\"font-size: 1em;\"><strong>H1-блокери (Първо поколение)</strong></td><td style=\"font-size: 1em;\">Изразена <font color=\"#dd0a0a\">седация</font>, <font color=\"#dd0a0a\">сънливост</font>, <font color=\"#dd0a0a\">замаяност</font>, <font color=\"#dd0a0a\">нарушение на вниманието, не трябва при шофьори.</font> <br>Антихолинергични ефекти: сухота в устата, запек, уринна ретенция, замъглено зрение.</td></tr><tr><td style=\"font-size: 1em;\"><strong>H1-блокери (Второ поколение)</strong></td><td style=\"font-size: 1em;\">Липса на седация (липофобни). Главоболие, умора. Минимален риск от аритмии при предозиране (удължен QT).</td></tr><tr><td style=\"font-size: 1em;\"><strong>H2-блокери</strong></td><td style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Диария</font>/<font color=\"#dd0a0a\">запек</font>, мускулни болки. <br>ЦНС: <font color=\"#dd0a0a\">объркване </font>(при възрастни). <br>Cimetidine: <font color=\"#dd0a0a\">антиандрогенен ефект </font>(<font color=\"#dd0a0a\">гинекомастия</font>, <font color=\"#dd0a0a\">импотентност</font>), <font color=\"#dd0a0a\">инхибира CYP450</font>.</td></tr><tr><td style=\"font-size: 1em;\"><strong>АСЕ-инхибитори</strong></td><td style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Суха кашлица</font></strong><font color=\"#dd0a0a\"> </font>(брадикинин). Хипотония при първа доза. <strong><font color=\"#dd0a0a\">Хиперкалиемия</font></strong>. <font color=\"#dd0a0a\">Ангиоедем</font>. <font color=\"#dd0a0a\">Тератогенност</font>. <font color=\"#dd0a0a\">Влошаване на бъбречната функция при стеноза на бъбречни артерии</font>.</td></tr><tr><td style=\"font-size: 1em;\"><strong>AT1-блокери (Сартани)</strong></td><td style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Подобни на АСЕ-инхибиторите, но </font><strong><font color=\"#dd0a0a\">БЕЗ суха кашлица</font></strong>. <font color=\"#dd0a0a\">Хиперкалиемия</font>, <font color=\"#dd0a0a\">хипотония</font>. <font color=\"#dd0a0a\">Тератогенност</font>.</td></tr><tr><td style=\"font-size: 1em;\"><strong>Алдостеронови антагонисти</strong></td><td style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Хиперкалиемия</font></strong>, метаболитна ацидоза. <br>Spironolactone: <font color=\"#dd0a0a\">Гинекомастия</font>, менструални нарушения (хормонален дисбаланс).</td></tr></tbody></table><h3 style=\"font-size: 1.1em;\">Лекарства действащи върху дихателна система:</h3><script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script><p style=\"font-size: 1em;\"><b>Бронходилататори</b>:<br></p><ul><li style=\"font-size: 1em;\"><b>b2-адреномиметици:</b></li><ul><li style=\"font-size: 1em;\">Кратко-действащи за пристъп: <b><font color=\"#dd0a0a\">Salbutamol</font></b>, Clenbuterol, <b>Hexoprenaline</b></li><li style=\"font-size: 1em;\">Дълго действащи: <b><font color=\"#dd0a0a\">Salmeterol</font></b>, Formoterol</li></ul><li style=\"font-size: 1em;\"><b>Метилксантини</b>: <font color=\"#dd0a0a\">Aminophylline</font>, <font color=\"#dd0a0a\">Theophylline</font>.</li><li style=\"font-size: 1em;\"><b>M-холиноблокери</b>: <font color=\"#dd0a0a\">Ipratropium</font>, <font color=\"#dd0a0a\">Tiotropium</font></li></ul>Противовъзпалителни лекарства:<ul><li style=\"font-size: 1em;\">Глюкокортикостероиди:</li><ul><li style=\"font-size: 1em;\">Инхалаторни: <font color=\"#dd0a0a\">Beclomethasone</font>, Fluticasone, Budesonide</li><li style=\"font-size: 1em;\">Системни: Prednisolone, Methylprednisolone</li></ul><li style=\"font-size: 1em;\">Левкотриенови рецепторни антагонисти: <font color=\"#dd0a0a\">Montelukast</font></li><li style=\"font-size: 1em;\">Моноклонални антитела срещу IgE: <font color=\"#dd0a0a\">Omalizumab</font>, Mepolizumab, Benrazumab</li></ul><p style=\"font-size: 1em;\"><b>Лекарства използвани при кашлица:</b></p><ul><li style=\"font-size: 1em;\"><b>Антитусивни</b>:</li><ul><li style=\"font-size: 1em;\">С централно действие: <font color=\"#dd0a0a\">Codeine</font>, Dextromethorphan, <font color=\"#dd0a0a\">Butamirate</font></li><li style=\"font-size: 1em;\">С периферно действие: <font color=\"#dd0a0a\">Penoxidiazine</font></li></ul><li style=\"font-size: 1em;\"><b>Отхрачващи лекарства</b>: <font color=\"#dd0a0a\">Ambroxol</font>, Bromhexine, <font color=\"#dd0a0a\">Acetylcysteine</font></li></ul><p style=\"font-size: 1em;\"><b>Лекарства за назално приложение:</b></p><ul><li style=\"font-size: 1em;\"><b>Деконгестанти</b>: <font color=\"#dd0a0a\">Xylomethazoline</font></li><li style=\"font-size: 1em;\"><b>Антиалергични и противовъзпалителни:</b></li><ul><li style=\"font-size: 1em;\">Кромогликати: Cromoglycic acid</li><li style=\"font-size: 1em;\">H1 блокери: Azelastine</li><li style=\"font-size: 1em;\">ГКС: Mometasone</li><li style=\"font-size: 1em;\">Антибиотици: Mupirocin, Fusafungine</li></ul></ul><h4 style=\"font-size: 1.05em;\">Лекарства действащи върху матката:</h4><p style=\"font-size: 1em;\"><b>Лекарства стимулиращи маточната активност:</b></p><ul><li style=\"font-size: 1em;\"><b>Хормони</b>: <font color=\"#dd0a0a\">Oxytocin</font></li><li style=\"font-size: 1em;\"><b>Простаноиди</b>: Carboprost, <font color=\"#dd0a0a\">Dinoprostone</font>, <font color=\"#dd0a0a\">Misoprostol</font></li><li style=\"font-size: 1em;\"><b>Лекарства, предизвикващи траен спазъм</b>: <font color=\"#dd0a0a\">Methylergometrine</font></li></ul><p style=\"font-size: 1em;\"><b>Лекарства, потискащи маточните контракции (токолитици):</b></p><ul><li style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Atosiban</font></li><li style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Nifedipine</font></li><li style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Hexoprenaline</font></li><li style=\"font-size: 1em;\">НСПВЛ</li></ul><h3 style=\"font-size: 1.1em;\">Лекарства действащи върху храносмилателната система:</h3><p style=\"font-size: 1em;\"><b>Противоязвени лекарствa</b></p><ul><li style=\"font-size: 1em;\"><b>Инхибитори на протонната помпа</b>:  <font color=\"#dd0a0a\">Omeprazole</font>, <font color=\"#dd0a0a\">Esomeprazole</font>, <font color=\"#dd0a0a\">Pantoprazole</font>, <font color=\"#dd0a0a\">Lansoprazole</font></li><li style=\"font-size: 1em;\"><b>H2 блокери:</b> <font color=\"#dd0a0a\">Ranitidine</font>, Famotidine, Nizatidine</li><li style=\"font-size: 1em;\"><b>Мукозни цитопротектори</b>: Colloidal bismuth subcitrate, Sucralfate</li><li style=\"font-size: 1em;\"><b>Простаноиди:</b>&nbsp;<font color=\"#dd0a0a\">Misoprostol</font></li><li style=\"font-size: 1em;\"><b>Антибактериални срещу H. Pylori</b>: <font color=\"#dd0a0a\">Clarithromycin</font>, <font color=\"#dd0a0a\">Amoxicillin</font>, <font color=\"#dd0a0a\">Metronidazole</font>, <font color=\"#dd0a0a\">Tetracycline</font></li><li style=\"font-size: 1em;\"><b>Антиацидни лекарства</b>: Sodium bicarbonate, Calcium carbonate, Magnesium hydroxide, Aluminium hydroxide</li><li style=\"font-size: 1em;\"><b>Лекарствени комбинации (примери)</b>: Almagel, Almagel А, Almalox, Stop-acid, Hydrotalcite</li></ul><b>Aнтиеметични лекарства:</b><br><ul><li style=\"font-size: 1em;\"><b>С централно действие:</b></li><ul><li style=\"font-size: 1em;\"><b>Допаминови антагонисти</b>: <font color=\"#dd0a0a\">Metoclopramide</font>, Domperidone, Haloperidol, Itopride</li><li style=\"font-size: 1em;\"><b>M-холинолитици</b>: <font color=\"#dd0a0a\">Scopolamine</font></li><li style=\"font-size: 1em;\"><b>H1 блокери с антиеметично действие</b>: <font color=\"#dd0a0a\">Dimenhydrinate</font></li><li style=\"font-size: 1em;\"><b>Серотонинови 5-HT3 блокери</b>: <font color=\"#dd0a0a\">Ondansetron</font>, Granisetron</li><li style=\"font-size: 1em;\"><b>Антагонисти на неврокинин NK1 рецептори (за субстанция P):</b> <font color=\"#dd0a0a\">Aprepitant</font>, Fosaprepitant</li><li style=\"font-size: 1em;\"><b>Канабиноиди</b>: Dronabinol, Nabilone</li><li style=\"font-size: 1em;\"><b>Глюкокортикостероиди</b>: Dexamethasone</li></ul><li style=\"font-size: 1em;\"><b>С периферно действие</b>: Sodium citrate</li></ul><p style=\"font-size: 1em;\"><b>Aпетитoстимулиращи лекарства:</b></p><ul><li style=\"font-size: 1em;\"><b>С централно действие</b>: <font color=\"#dd0a0a\">Cyproheptadine </font></li><li style=\"font-size: 1em;\"><b>С периферно действие – горчиви вещeвства</b>: Herba Gentianae, herba Absinthii</li></ul><p style=\"font-size: 1em;\"><b>Антиобезни лекарства:</b></p><ul><li style=\"font-size: 1em;\"><b>С централно действие</b>: <font color=\"#dd0a0a\">Liraglutide</font>, Naltrexone/bupropion</li><li style=\"font-size: 1em;\"><b>С периферно действие</b>: Orlistat</li></ul><p style=\"font-size: 1em;\"><b>Лекарства, повлияващи чревния мотилитет:</b></p><ul><li style=\"font-size: 1em;\"><b><p style=\"font-size: 1em;\">Лекарства, стимулиращи перисталтиката на проксималния отдел на стомашно-чревния тракт </p><p style=\"font-size: 1em;\">(прокинетици): </p></b><font color=\"#dd0a0a\">Metoclopramide</font>, Domperidone, Itopride</li><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><b>Oчистителни лекарства (Laxativа):</b> </p>Macrogol, <font color=\"#dd0a0a\">Mannitol</font>, Magnesium sulfate, Oleum Ricini, <font color=\"#dd0a0a\">Lactulose</font>, <font color=\"#dd0a0a\">Bicosodyl</font>, Sodium picosulphate, Laxal, Sennoside</li></ul><p style=\"font-size: 1em;\"><b>Антидиарични лекарства</b>: Loperamide, Racecadotril, Diosmectite</p><p style=\"font-size: 1em;\"><b>Спазмолитици:</b></p><ul><li style=\"font-size: 1em;\"><b>М-холинолитици:</b> Butylscopolamine, Atropine</li><li style=\"font-size: 1em;\"><b>Папаверин и аналози</b>: Papaverine, Drotaverine, Mebeverine</li></ul><p style=\"font-size: 1em;\"><b>Газогонни (карминативни) лекарства</b>: Simethicone</p><p style=\"font-size: 1em;\"><b>Антиколитни лекарства:</b></p><ul><li style=\"font-size: 1em;\"><b>Аминосалицилати: </b>Mesalazine, Sulfasalazine</li><li style=\"font-size: 1em;\"><b>Глюкокортикостероиди: </b>Prednisolone, Budesonide</li><li style=\"font-size: 1em;\"><b>Имуносупресори: </b>Azathioprine, Methotrexate, 6-mercaptopurine</li><li style=\"font-size: 1em;\"><b>Анти-TNF терапия: </b>Infliximab, Adalimumab, Cetrolizumab, Golimumab</li><li style=\"font-size: 1em;\"><b>Антиингенонова терапия: </b>Natalizumab</li></ul><p style=\"font-size: 1em;\"><b>Панкреатични ензими:</b> Panreactine, Multienzymes (lipsase, protease - Kreon, Panzytrat)</p><p style=\"font-size: 1em;\"><b>Хепатопротективни лекарства: </b><font color=\"#dd0a0a\">Silymarin</font>, Ademethionine, L-ornitine-L-aspartate</p>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\r\n<script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\r\n<script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script>\r\n</body>\r\n</html>";
